('laravel-cache-setting_about_experience','a:5:{i:0;a:6:{s:6:\"period\";s:18:\"Mar 2023 - Present\";s:5:\"title\";s:20:\"Full Stack Developer\";s:7:\"company\";s:8:\"IDEATION\";s:11:\"description\";s:394:\"Collaborate with cross-functional teams to develop and maintain digital solutions for major Pakistani telecom operators including Jazz, Telenor, and Zong. Delivered OTT platforms (Zong Mobile TV, Deikhlo), an AI assistant platform (OZGPT), cloud storage portals, IVR backend systems, and live sports streaming infrastructure handling massive concurrent traffic spikes during PSL and ICC events.\";s:5:\"color\";s:4:\"teal\";s:4:\"tags\";a:6:{i:0;s:7:\"Laravel\";i:1;s:7:\"FastAPI\";i:2;s:5:\"MySQL\";i:3;s:3:\"HLS\";i:4;s:2:\"AI\";i:5;s:7:\"Node.js\";}}i:1;a:6:{s:6:\"period\";s:19:\"Mar 2022 - Mar 2023\";s:5:\"title\";s:24:\"Chief Technology Officer\";s:7:\"company\";s:15:\"X3 Technologies\";s:11:\"description\";s:383:\"Co-founded a tech startup and spearheaded product development alongside a partner. Secured pre-seed funding including office space and salary cover, plus a significant equity stake, to build a supply chain solution. Validated the product concept through rapid iteration and gained deep first-hand exposure to the startup ecosystem: product-market fit, fundraising, and team building.\";s:5:\"color\";s:6:\"sunset\";s:4:\"tags\";a:3:{i:0;s:21:\"Technology Leadership\";i:1;s:16:\"Product Strategy\";i:2;s:11:\"Fundraising\";}}i:2;a:6:{s:6:\"period\";s:19:\"Jan 2022 - Mar 2023\";s:5:\"title\";s:19:\"Technical Team Lead\";s:7:\"company\";s:22:\"Business Partner Group\";s:11:\"description\";s:483:\"Joined as Full Stack Developer building a real estate platform for the Australian market, connecting brokers, sellers, and buyers using Laravel and React.js. Promoted to Technical Team Lead within 3 months following a CEO anonymous evaluation recognising performance, communication, and technical expertise. In the lead role, conducted daily CEO briefings, resolved development blockages, maintained 100% project alignment, and reduced communication delays across a distributed team.\";s:5:\"color\";s:4:\"teal\";s:4:\"tags\";a:5:{i:0;s:7:\"Laravel\";i:1;s:8:\"React.js\";i:2;s:5:\"MySQL\";i:3;s:5:\"Scrum\";i:4;s:15:\"Team Leadership\";}}i:3;a:6:{s:6:\"period\";s:19:\"May 2021 - Mar 2022\";s:5:\"title\";s:15:\"Project Manager\";s:7:\"company\";s:9:\"Wing Sols\";s:11:\"description\";s:399:\"Led the software development team managing tasks, facilitating daily standups, and using Trello and Excel for project tracking. Secured 100% new clients through Upwork and direct outreach. Collaborated with leadership on progress updates and ensured team-company alignment. Secured the role by leveraging volunteer experience and demonstrating strong communication and stakeholder engagement skills.\";s:5:\"color\";s:6:\"sunset\";s:4:\"tags\";a:4:{i:0;s:18:\"Project Management\";i:1;s:5:\"Agile\";i:2;s:20:\"Business Development\";i:3;s:6:\"Upwork\";}}i:4;a:6:{s:6:\"period\";s:18:\"Dec 2018 - Ongoing\";s:5:\"title\";s:19:\"Freelance Developer\";s:7:\"company\";s:11:\"Independent\";s:11:\"description\";s:326:\"Ongoing freelance practice running in parallel with full-time roles. Building custom web applications for clients across e-commerce, telecom, education, and healthcare. Delivering end-to-end solutions covering frontend, backend, database design, and deployment using the MERN stack, Laravel, FastAPI, and related technologies.\";s:5:\"color\";s:4:\"teal\";s:4:\"tags\";a:5:{i:0;s:7:\"Laravel\";i:1;s:10:\"MERN Stack\";i:2;s:7:\"FastAPI\";i:3;s:9:\"REST APIs\";i:4;s:5:\"CI/CD\";}}}',1779451224),
