insert  into `product_pages`(`id`,`project_id`,`title`,`slug`,`type`,`content`,`is_published`,`sort_order`,`created_at`,`updated_at`) values 
(1,7,'Get Started','setup','setup','{\"heading\":\"Congratulations!\",\"message\":\"Thank you for purchasing BioLink Pro. Choose how you\'d like to get started below.\",\"options\":[{\"title\":\"Download Source Code\",\"description\":\"Download the full source code and deploy manually to your own server or hosting provider. Best for developers who want full control.\",\"icon\":\"star\",\"button_label\":\"Download Files\",\"button_url\":\"https:\\/\\/github.com\\/adisher\\/portfolio-one\\/releases\",\"recommended\":false},{\"title\":\"Deploy to Vercel\",\"description\":\"One-click deploy to Vercel with automatic GitHub repository setup. The fastest way to get your BioLink page live. Free hosting included.\",\"icon\":\"star\",\"button_label\":\"Start Deploy Guide\",\"button_url\":\"\\/products\\/biolink-pro\\/deploy\",\"recommended\":true}]}',1,0,'2026-03-01 23:02:11','2026-03-02 00:05:13'),
(2,7,'Deploy to Vercel','deploy','deploy','{\"heading\":\"Deploy to Vercel\",\"steps\":[{\"title\":\"Prerequisites\",\"description\":\"Before you begin, make sure you have accounts on these platforms.\",\"items\":\"Create a free GitHub account at https:\\/\\/github.com\\r\\nCreate a free Vercel account at https:\\/\\/vercel.com\\r\\nSign into Vercel using your GitHub account\",\"button_label\":\"Open GitHub\",\"button_url\":\"https:\\/\\/github.com\\/signup\",\"guidance\":\"If you already have these accounts, you can skip this step.\",\"note\":\"\"},{\"title\":\"Deploy to Vercel\",\"description\":\"Click the button below to clone the BioLink Pro repository to your GitHub and deploy it to Vercel automatically.\",\"items\":\"Click the Deploy button below\\r\\nAuthorize Vercel to access your GitHub\\r\\nChoose a repository name\\r\\nClick Deploy\",\"button_label\":\"Deploy to Vercel\",\"button_url\":\"https:\\/\\/vercel.com\\/new\\/clone?repository-url=https:\\/\\/github.com\\/adisher\\/portfolio-one\",\"guidance\":\"The deployment process typically takes 1-2 minutes.\",\"note\":\"Vercel will create a new repository in your GitHub account and deploy it automatically.\"},{\"title\":\"Visit Your Live Site\",\"description\":\"Once deployment is complete, Vercel will provide you with a live URL. Click \\\"Visit\\\" to see your BioLink page.\",\"items\":\"Wait for deployment to complete\\r\\nClick the Visit button on Vercel\\r\\nYour BioLink page is now live!\",\"button_label\":\"\",\"button_url\":\"\",\"guidance\":\"Your URL will look like: your-site.vercel.app\",\"note\":\"\"},{\"title\":\"Set Your Admin Password\",\"description\":\"Navigate to your site\'s admin panel to set up your password on first visit.\",\"items\":\"Go to your-site.vercel.app\\/admin-setup\\r\\nCreate your admin password\\r\\nLog in to the admin dashboard\",\"button_label\":\"\",\"button_url\":\"\",\"guidance\":\"Save your password somewhere safe. You\'ll need it to manage your BioLink page.\",\"note\":\"The first visit to \\/admin-setup will prompt you to create a password. This only happens once.\"},{\"title\":\"Customize Your Page\",\"description\":\"Use the admin panel to personalize your BioLink page with your content.\",\"items\":\"Upload your profile photo\\r\\nUpdate your bio and display name\\r\\nAdd your social links\\r\\nChoose a theme preset\\r\\nCustomize colors to match your brand\",\"button_label\":\"\",\"button_url\":\"\",\"guidance\":\"All changes are saved instantly and reflected on your live page.\",\"note\":\"\"},{\"title\":\"Connect Custom Domain (Optional)\",\"description\":\"Want to use your own domain? Connect it through your Vercel dashboard.\",\"items\":\"Go to your Vercel project settings\\r\\nClick on Domains\\r\\nAdd your custom domain\\r\\nUpdate DNS records as instructed\",\"button_label\":\"Vercel Domain Docs\",\"button_url\":\"https:\\/\\/vercel.com\\/docs\\/projects\\/domains\",\"guidance\":\"DNS propagation can take up to 48 hours, but usually completes within minutes.\",\"note\":\"You\'ll need to own a domain name. If you don\'t have one, you can purchase from Namecheap, GoDaddy, or Cloudflare.\"}],\"support_heading\":\"Need Help?\",\"support_message\":\"If you run into any issues during deployment, don\'t hesitate to reach out. We\'re here to help!\",\"support_url\":null}',1,1,'2026-03-01 23:02:11','2026-03-02 00:25:05');
