(24,'about_skills','[{\"title\":\"Frontend Development\",\"description\":\"Modern, responsive interfaces\",\"color\":\"teal\",\"tags\":[\"JavaScript\",\"Vue.js\",\"Tailwind CSS\"]},{\"title\":\"Backend Development\",\"description\":\"Scalable server-side solutions\",\"color\":\"sunset\",\"tags\":[\"Laravel\",\"PHP\",\"FastAPI\",\"Python\"]},{\"title\":\"Database & DevOps\",\"description\":\"Data management and deployment\",\"color\":\"teal\",\"tags\":[\"MySQL\",\"Docker\",\"AWS\"]}]','array','about','Skills','Skill category cards',NULL,6,1,'2026-05-19 14:35:53','2026-05-19 14:35:53'),
(25,'about_experience','[{\"period\":\"Mar 2023 - Present\",\"title\":\"Full Stack Developer\",\"company\":\"IDEATION\",\"description\":\"Collaborate with cross-functional teams to develop and maintain digital solutions for major Pakistani telecom operators including Jazz, Telenor, and Zong. Delivered OTT platforms (Zong Mobile TV, Deikhlo), an AI assistant platform (OZGPT), cloud storage portals, IVR backend systems, and live sports streaming infrastructure handling massive concurrent traffic spikes during PSL and ICC events.\",\"color\":\"teal\",\"tags\":[\"Laravel\",\"FastAPI\",\"MySQL\",\"HLS\",\"AI\",\"Node.js\"]},{\"period\":\"Mar 2022 - Mar 2023\",\"title\":\"Chief Technology Officer\",\"company\":\"X3 Technologies\",\"description\":\"Co-founded a tech startup and spearheaded product development alongside a partner. Secured pre-seed funding including office space and salary cover, plus a significant equity stake, to build a supply chain solution. Validated the product concept through rapid iteration and gained deep first-hand exposure to the startup ecosystem: product-market fit, fundraising, and team building.\",\"color\":\"sunset\",\"tags\":[\"Technology Leadership\",\"Product Strategy\",\"Fundraising\"]},{\"period\":\"Jan 2022 - Mar 2023\",\"title\":\"Technical Team Lead\",\"company\":\"Business Partner Group\",\"description\":\"Joined as Full Stack Developer building a real estate platform for the Australian market, connecting brokers, sellers, and buyers using Laravel and React.js. Promoted to Technical Team Lead within 3 months following a CEO anonymous evaluation recognising performance, communication, and technical expertise. In the lead role, conducted daily CEO briefings, resolved development blockages, maintained 100% project alignment, and reduced communication delays across a distributed team.\",\"color\":\"teal\",\"tags\":[\"Laravel\",\"React.js\",\"MySQL\",\"Scrum\",\"Team Leadership\"]},{\"period\":\"May 2021 - Mar 2022\",\"title\":\"Project Manager\",\"company\":\"Wing Sols\",\"description\":\"Led the software development team managing tasks, facilitating daily standups, and using Trello and Excel for project tracking. Secured 100% new clients through Upwork and direct outreach. Collaborated with leadership on progress updates and ensured team-company alignment. Secured the role by leveraging volunteer experience and demonstrating strong communication and stakeholder engagement skills.\",\"color\":\"sunset\",\"tags\":[\"Project Management\",\"Agile\",\"Business Development\",\"Upwork\"]},{\"period\":\"Dec 2018 - Ongoing\",\"title\":\"Freelance Developer\",\"company\":\"Independent\",\"description\":\"Ongoing freelance practice running in parallel with full-time roles. Building custom web applications for clients across e-commerce, telecom, education, and healthcare. Delivering end-to-end solutions covering frontend, backend, database design, and deployment using the MERN stack, Laravel, FastAPI, and related technologies.\",\"color\":\"teal\",\"tags\":[\"Laravel\",\"MERN Stack\",\"FastAPI\",\"REST APIs\",\"CI\\/CD\"]}]','array','about','Experience','Career timeline entries',NULL,7,1,'2026-05-19 14:35:53','2026-05-20 01:17:05'),
(26,'about_values','[{\"title\":\"Innovation\",\"description\":\"Embracing cutting-edge technologies to create modern solutions\",\"color\":\"teal\"},{\"title\":\"Quality\",\"description\":\"Writing clean, maintainable code that stands the test of time\",\"color\":\"sunset\"},{\"title\":\"Collaboration\",\"description\":\"Working closely with clients and teams to deliver the right outcome\",\"color\":\"teal\"},{\"title\":\"Performance\",\"description\":\"Optimising for speed, scalability, and user experience at every layer\",\"color\":\"sunset\"}]','array','about','Values','Philosophy cards',NULL,8,1,'2026-05-19 14:35:53','2026-05-19 14:35:53');
