insert  into `testimonials`(`id`,`type`,`client_name`,`client_position`,`client_company`,`client_role`,`role_description`,`client_website`,`client_linkedin`,`testimonial`,`client_image`,`rating`,`country_code`,`country_name`,`city`,`latitude`,`longitude`,`is_featured`,`is_published`,`sort_order`,`created_at`,`updated_at`) values 
(1,'client','Asko','CEO',NULL,NULL,NULL,NULL,NULL,'Excellent Contractor to work with. I am extremely happy with the final result, the work surpassed my expectations. I would highly recommend using this contractor. He is super responsive and technically proficient in what he does!!! Thanks..',NULL,5,'UK','United Kingdom','London',51.50735100,-0.12775800,0,0,1,'2026-02-01 11:53:33','2026-02-05 18:26:52'),
(2,'client','Darius Naghavi','CEO','Business Partner Group','Full Stack Developer → Promoted to Team Lead In Three Months','Led platform development while coordinating daily CEO briefings and team alignment to ensure smooth, reliable project delivery.','https://www.lionsbusinessbrokers.com/','https://linkedin.com/company/business-partner-group/','Adil carries the command and judgment of a veteran with decades in the field. Hired as a full-stack developer, his leadership quickly earned him a promotion to Project Manager. In my 40 years of experience, that level of skill and reliability is rare.',NULL,5,'AU','Australia','Brisbane',-25.27439900,133.77513100,1,1,1,'2026-02-05 01:20:29','2026-02-25 19:32:31'),
(3,'client','Tayyab Rehman','Former CEO','Wingsols','Project Manager','Led software development team, coordinated daily meetings, managed client-facing deliverables and drove new business through client acquisition to ensure reliable project execution and alignment with company goals.',NULL,'https://www.linkedin.com/company/wing-sols/about/','Adil brings exceptional project management and analytical skills to every task. His approach is marked by a strong ethical framework, ensuring transparency and integrity in all his projects. I have no doubt that he will continue to excel and be a significant contributor wherever he goes.',NULL,5,'AE','UAE','Dubai',25.20484900,55.27078200,1,1,3,'2026-02-05 18:35:09','2026-02-25 20:06:15'),
(4,'colleague','Shariq Saleem','Senior Sales & Business Consultant',NULL,NULL,NULL,NULL,'https://www.linkedin.com/in/mshariqs/','Adil stands out as one of the most exceptional resources I\'ve encountered. He embodies both genuine courtesy and impressive professionalism. He possesses a deep understanding of how to accomplish tasks efficiently and consistently meets deadlines. Adil is someone you can undoubtedly rely on, and I extend my best wishes and prayers for his continued success.',NULL,5,'QA','Qatar','Doha',25.35482600,51.18388400,1,1,3,'2026-02-27 00:03:02','2026-02-27 00:03:02');
